/* ── Reset & base ─────────────────────────────────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --bg:       #0f1117;
  --surface:  #1a1d27;
  --border:   #2a2d3a;
  --text:     #d4d8e8;
  --dim:      #6b7080;
  --accent:   #6c8cf5;
  --green:    #4caf82;
  --red:      #e05c5c;
  --yellow:   #e0b84a;
  --agent-a:  #7eb8f7;
  --agent-b:  #b07ef7;
  --font:     "SF Mono", "Fira Code", "Consolas", monospace;
}

html { font-size: 14px; }
body { background: var(--bg); color: var(--text); font-family: var(--font); line-height: 1.5; }

a { color: var(--accent); text-decoration: none; }
a:hover { text-decoration: underline; }
code, pre { font-family: var(--font); font-size: 0.85rem; }
pre { white-space: pre-wrap; word-break: break-all; }

/* ── Page shell ───────────────────────────────────────────────────────────── */
.page { max-width: 1200px; margin: 0 auto; padding: 2rem 1.5rem; }

header {
  display: flex;
  align-items: baseline;
  gap: 1rem;
  margin-bottom: 1.5rem;
  flex-wrap: wrap;
}
header h1 { font-size: 1.4rem; font-weight: 600; letter-spacing: -0.02em; }
.subtitle { color: var(--dim); }
.back { font-size: 0.85rem; color: var(--dim); margin-right: auto; }
.header-actions { margin-left: auto; }

/* ── Buttons ──────────────────────────────────────────────────────────────── */
.btn, .btn-small {
  display: inline-block;
  padding: 0.35rem 0.75rem;
  border: 1px solid var(--border);
  border-radius: 4px;
  color: var(--text);
  font-size: 0.8rem;
  background: var(--surface);
  cursor: pointer;
}
.btn:hover, .btn-small:hover { border-color: var(--accent); text-decoration: none; }

/* ── Badges ───────────────────────────────────────────────────────────────── */
.badge {
  display: inline-block;
  padding: 0.1rem 0.5rem;
  border-radius: 3px;
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}
.badge--success    { background: #1a3d2b; color: var(--green); }
.badge--turn_limit { background: #2d2a1a; color: var(--yellow); }
.badge--stuck      { background: #3d1a1a; color: var(--red); }
.badge--unknown    { background: var(--surface); color: var(--dim); }

/* ── Runs table ───────────────────────────────────────────────────────────── */
.runs-table {
  width: 100%;
  border-collapse: collapse;
}
.runs-table th, .runs-table td {
  padding: 0.55rem 0.75rem;
  text-align: left;
  border-bottom: 1px solid var(--border);
}
.runs-table th { color: var(--dim); font-weight: 500; font-size: 0.8rem; }
.runs-table tr:hover td { background: var(--surface); }

.empty { color: var(--dim); margin-top: 2rem; }
.empty code { color: var(--text); }

/* ── Summary bar ──────────────────────────────────────────────────────────── */
.summary-bar {
  display: flex;
  gap: 2rem;
  padding: 0.75rem 1rem;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 6px;
  margin-bottom: 1.25rem;
  font-size: 0.85rem;
  flex-wrap: wrap;
}
.summary-bar .warn strong { color: var(--yellow); }

/* ── Workspace ────────────────────────────────────────────────────────────── */
.workspace {
  display: grid;
  grid-template-columns: 280px 1fr;
  gap: 1rem;
  height: calc(100vh - 220px);
  min-height: 400px;
}

/* ── Timeline ─────────────────────────────────────────────────────────────── */
.timeline {
  overflow-y: auto;
  border: 1px solid var(--border);
  border-radius: 6px;
  background: var(--surface);
}

.tl-row {
  display: grid;
  grid-template-columns: 36px 24px 1fr 20px 20px;
  align-items: center;
  gap: 0.4rem;
  padding: 0.45rem 0.6rem;
  cursor: pointer;
  border-bottom: 1px solid var(--border);
  font-size: 0.8rem;
}
.tl-row:last-child { border-bottom: none; }
.tl-row:hover { background: rgba(108,140,245,0.07); }
.tl-row--active { background: rgba(108,140,245,0.15) !important; }
.tl-row--diverge { border-left: 2px solid var(--yellow); }

.tl-turn { color: var(--dim); text-align: right; }
.tl-agent { font-weight: 700; text-align: center; }
.tl-tool  { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.tl-status.ok   { color: var(--green); }
.tl-status.fail { color: var(--red); }
.tl-flag  { color: var(--yellow); font-size: 0.75rem; }

.agent-A { color: var(--agent-a); }
.agent-B { color: var(--agent-b); }

/* ── Detail panel ─────────────────────────────────────────────────────────── */
.detail-panel {
  overflow-y: auto;
  border: 1px solid var(--border);
  border-radius: 6px;
  background: var(--surface);
  padding: 1rem 1.25rem;
  font-size: 0.85rem;
}

.hint { color: var(--dim); margin-top: 2rem; text-align: center; }

.detail-header {
  display: flex;
  gap: 1.25rem;
  align-items: center;
  margin-bottom: 1rem;
  padding-bottom: 0.75rem;
  border-bottom: 1px solid var(--border);
  flex-wrap: wrap;
}
.detail-header .dim { color: var(--dim); }
.mono { font-family: var(--font); }

.section { margin-top: 1.1rem; }
.section h3 { font-size: 0.75rem; font-weight: 600; text-transform: uppercase; letter-spacing: 0.06em; color: var(--dim); margin-bottom: 0.5rem; }
.section pre { background: rgba(0,0,0,0.25); padding: 0.5rem 0.75rem; border-radius: 4px; margin-top: 0.25rem; }

.kv { display: flex; gap: 0.75rem; margin-bottom: 0.3rem; align-items: flex-start; }
.kv > span:first-child { color: var(--dim); min-width: 80px; flex-shrink: 0; }

/* ── Divergences ──────────────────────────────────────────────────────────── */
.diverge-section {
  background: rgba(224, 184, 74, 0.07);
  border: 1px solid rgba(224, 184, 74, 0.3);
  border-radius: 5px;
  padding: 0.75rem 1rem;
}
.diverge-section h3 { color: var(--yellow); }
.diverge-item {
  display: flex;
  gap: 0.75rem;
  flex-wrap: wrap;
  margin-top: 0.35rem;
  font-size: 0.8rem;
}
.div-type { color: var(--yellow); font-weight: 600; min-width: 160px; }

/* ── Mini grid ────────────────────────────────────────────────────────────── */
.collapsible-body.hidden { display: none; }
.collapsible-toggle { cursor: pointer; user-select: none; }
.collapsible-toggle:hover { color: var(--text); }

.mini-grid { display: inline-flex; flex-direction: column; gap: 2px; margin-top: 0.5rem; }
.mini-row  { display: flex; gap: 2px; }
.mini-cell {
  width: 24px; height: 24px;
  display: flex; align-items: center; justify-content: center;
  font-size: 0.7rem; font-weight: 700;
  border-radius: 3px;
}
.c-wall  { background: #2a2d3a; color: var(--dim); }
.c-empty { background: #191c26; color: var(--dim); }
.c-key   { background: #2d2a1a; color: var(--yellow); }
.c-door  { background: #3d1a1a; color: var(--red); }
.c-open  { background: #1a3d2b; color: var(--green); }
.c-exit  { background: #1a2d3d; color: var(--accent); }
.c-agent { background: #2a1a3d; color: var(--agent-b); }

