  .  empty floor
  #  wall (impassable)
  K  key (pick it up)
  D  locked door (needs key to open — use_item key door when adjacent)
  O  open door (passable)
  E  exit (goal — reach it to win)
  A / B  the two agents

Rules:
- You can only see cells adjacent to you (fog of war).
- Moves into walls or locked doors fail silently.
- The door must be unlocked before either agent can pass through it.
- Only ONE agent needs the key; they unlock the door so both can proceed.
- Messages you send arrive on the OTHER agent's NEXT turn, not instantly.
- You MUST call exactly one tool per turn. Do not explain yourself — just call the tool.

Your agent ID: {agent_id}
"""


class Agent:
    def __init__(self, agent_id: str, model: str = "gpt-4o-mini"):
        self.agent_id = agent_id
        self.model = model
        self.message_inbox: list[str] = []    # messages received this turn
        self.message_outbox: list[str] = []   # messages to deliver next turn
        self.conversation_history: list[dict] = []

    # ------------------------------------------------------------------
    # Decision
    # ------------------------------------------------------------------

    def decide(self, observable_state: dict, messages_received: list[str]) -> tuple[dict, str, str, int]:
        """
        Returns (tool_call_dict, full_prompt_str, raw_response_str, latency_ms)
        """
        obs_text = _format_observation(observable_state, messages_received)

        # Build messages for this turn (stateless per turn — keeps context window predictable)
        messages = [
            {"role": "system", "content": SYSTEM_PROMPT.format(agent_id=self.agent_id)},
            {"role": "user",   "content": obs_text},
        ]

        start = time.time()
        response = _client.chat.completions.create(
            model=self.model,
            messages=messages,
            tools=TOOLS,
            tool_choice="required",
        )
        latency_ms = int((time.time() - start) * 1000)

        raw_response = response.model_dump_json()
        choice = response.choices[0]

        # Extract tool call
        tool_call = choice.message.tool_calls[0] if choice.message.tool_calls else None
        if tool_call is None:
            # Fallback: look if no tool was chosen
            tool_dict = {"tool": "look", "args": {}}
        else:
            try:
                args = json.loads(tool_call.function.arguments)
            except json.JSONDecodeError:
                args = {}
            tool_dict = {"tool": tool_call.function.name, "args": args}

        return tool_dict, obs_text, raw_response, latency_ms


# ------------------------------------------------------------------
# Helpers
# ------------------------------------------------------------------

def _format_observation(obs: dict, messages: list[str]) -> str:
    lines = [
        f"Your position: {obs['position']}",
        f"Inventory: {obs['inventory'] or 'empty'}",
        f"Door unlocked: {obs['door_unlocked']}",
        "",
        "Visible cells (row,col → cell):",
    ]
    for coord, cell in sorted(obs["visible_cells"].items()):
        lines.append(f"  {coord} → {cell}")

    if obs["other_agent_visible"]:
        lines.append(f"\nOther agent is visible at {obs['other_agent_position']}")
    else:
        lines.append("\nOther agent is not in view")

    if messages:
        lines.append("\nMessages received this turn:")
        for m in messages:
            lines.append(f"  - {m}")
    else:
        lines.append("\nNo messages received this turn.")

    lines.append("\nWhat do you do? Call exactly one tool.")
    return "\n".join(lines)

