/* ── Reset ─────────────────────────────────────────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --bg:       #0f1117;
  --surface:  #161920;
  --surface2: #1d2030;
  --border:   #252832;
  --text:     #d4d8e8;
  --dim:      #5a6070;
  --accent:   #6c8cf5;
  --green:    #4caf82;
  --red:      #e05c5c;
  --yellow:   #e0b84a;
  --agent-a:  #7eb8f7;
  --agent-b:  #b07ef7;
  --font:     "SF Mono", "Fira Code", "Consolas", monospace;
}

html, body { height: 100%; }
body {
  background: var(--bg);
  color: var(--text);
  font-family: var(--font);
  font-size: 13px;
  line-height: 1.5;
  display: flex;
  flex-direction: column;
}

a { color: var(--accent); text-decoration: none; }
a:hover { text-decoration: underline; }
code, pre { font-family: var(--font); font-size: 0.85em; }

/* ── App shell ─────────────────────────────────────────────────────────────── */
.app {
  display: flex;
  flex-direction: column;
  height: 100vh;
  overflow: hidden;
}

/* ── Header ────────────────────────────────────────────────────────────────── */
.header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0.65rem 1.25rem;
  border-bottom: 1px solid var(--border);
  background: var(--surface);
  flex-shrink: 0;
  gap: 1rem;
  flex-wrap: wrap;
}
.header-left { display: flex; align-items: baseline; gap: 0.75rem; }
.header h1 { font-size: 1rem; font-weight: 700; letter-spacing: -0.01em; }
.run-id-label { font-size: 0.75rem; color: var(--dim); }

.header-controls {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  flex-wrap: wrap;
}
.ctrl-label {
  display: flex;
  align-items: center;
  gap: 0.4rem;
  font-size: 0.75rem;
  color: var(--dim);
}
.ctrl-label input {
  width: 80px;
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: 4px;
  color: var(--text);
  font-family: var(--font);
  font-size: 0.8rem;
  padding: 0.25rem 0.5rem;
}
.ctrl-label input:focus { outline: none; border-color: var(--accent); }

/* ── Buttons ───────────────────────────────────────────────────────────────── */
.btn-run {
  background: var(--accent);
  color: #fff;
  border: none;
  border-radius: 4px;
  padding: 0.35rem 0.85rem;
  font-family: var(--font);
  font-size: 0.8rem;
  font-weight: 600;
  cursor: pointer;
  letter-spacing: 0.02em;
}
.btn-run:hover:not(:disabled)  { background: #849af7; }
.btn-run:disabled { opacity: 0.5; cursor: not-allowed; }

.btn-small {
  display: inline-block;
  padding: 0.25rem 0.6rem;
  border: 1px solid var(--border);
  border-radius: 3px;
  color: var(--text);
  font-size: 0.75rem;
  background: var(--surface);
  cursor: pointer;
}
.btn-small:hover:not(:disabled) { border-color: var(--accent); text-decoration: none; }
.btn-small:disabled { opacity: 0.4; cursor: not-allowed; pointer-events: none; }

/* ── Status bar ────────────────────────────────────────────────────────────── */
.status-bar {
  display: flex;
  align-items: center;
  gap: 1rem;
  padding: 0.45rem 1.25rem;
  border-bottom: 1px solid var(--border);
  background: var(--surface);
  flex-shrink: 0;
  flex-wrap: wrap;
}
.status-item { font-size: 0.8rem; color: var(--dim); }
.warn        { color: var(--yellow); }
.hidden      { display: none !important; }
.header-right-actions { margin-left: auto; }

.milestones { display: flex; gap: 0.5rem; flex-wrap: wrap; }
.milestone {
  font-size: 0.7rem;
  padding: 0.15rem 0.5rem;
  border-radius: 3px;
  font-weight: 600;
}
.ms-key  { background: rgba(224,184,74,0.15);  color: var(--yellow); }
.ms-door { background: rgba(76,175,130,0.15);  color: var(--green); }
.ms-exit { background: rgba(108,140,245,0.15); color: var(--accent); }

/* ── Badges ────────────────────────────────────────────────────────────────── */
.badge {
  display: inline-block;
  padding: 0.12rem 0.5rem;
  border-radius: 3px;
  font-size: 0.7rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}
.badge--idle       { background: var(--surface2); color: var(--dim); }
.badge--running    { background: rgba(108,140,245,0.2); color: var(--accent); }
.badge--success    { background: rgba(76,175,130,0.2);  color: var(--green); }
.badge--turn_limit { background: rgba(224,184,74,0.2);  color: var(--yellow); }
.badge--stuck      { background: rgba(224,92,92,0.2);   color: var(--red); }
.badge--error      { background: rgba(224,92,92,0.2);   color: var(--red); }
.badge--unknown    { background: var(--surface2); color: var(--dim); }

/* ── Workspace ─────────────────────────────────────────────────────────────── */
.workspace {
  display: grid;
  grid-template-columns: 42% 1fr;
  flex: 1;
  overflow: hidden;
  gap: 0;
}

/* ── Panel shared ──────────────────────────────────────────────────────────── */
.panel-title {
  font-size: 0.7rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--dim);
  padding: 0.55rem 1rem;
  border-bottom: 1px solid var(--border);
  display: flex;
  align-items: baseline;
  gap: 0.6rem;
}
.panel-subtitle { font-weight: 400; letter-spacing: 0; text-transform: none; font-size: 0.7rem; }

