                "divergences":       dm_event["divergences"],
                "latency_ms":        dm_result["latency_ms"],
            })

        return {
            "success":    True,
            "queued_for": agent_id,
            "on_turn":    "next",
            "staleness":  dm_result["actual_staleness"],
        }

    def _both_at_exit(self) -> bool:
        return self.world.is_at_exit("A") and self.world.is_at_exit("B")

