    <span>${data.total_turns} turns · ${divergeCount} divergence${divergeCount !== 1 ? "s" : ""} detected</span>
  `;
  document.getElementById("event-log").appendChild(banner);
  scrollLog();

  // Show analysis panel with loading state
  const panel = document.getElementById("analysis-panel");
  panel.classList.remove("hidden");
  document.getElementById("analysis-body").innerHTML =
    '<div class="analysis-loading">⏳ Generating analysis…</div>';

  loadRunHistory();
}

// ── analysis ──────────────────────────────────────────────────────────────────
function onAnalysis(data) {
  if (evtSource) { evtSource.close(); evtSource = null; }

  const failureType = data.failure_type || "unknown";
  const badgeClass  = {
    success:      "badge--success",
    single_agent: "badge--turn_limit",
    interaction:  "badge--turn_limit",
    emergent:     "badge--stuck",
  }[failureType] || "badge--unknown";

  document.getElementById("analysis-failure-badge").innerHTML =
    `<span class="badge ${badgeClass}">${failureType.replace(/_/g, " ")}</span>`;
  document.getElementById("analysis-subtitle").textContent = "";

  const suggestions = (data.what_should_change || "")
    .split("\n")
    .filter(l => l.trim())
    .map(l => `<li>${l.replace(/^-\s*/, "")}</li>`)
    .join("");

  document.getElementById("analysis-body").innerHTML = `
    <div class="analysis-grid">
      <div class="analysis-section">
        <div class="analysis-label">What happened</div>
        <p>${data.what_happened || "—"}</p>
      </div>
      <div class="analysis-section">
        <div class="analysis-label">Why it happened</div>
        <p>${data.why_it_happened || "—"}</p>
      </div>
      <div class="analysis-section analysis-section--wide">
        <div class="analysis-label">What should change</div>
        <ul class="analysis-suggestions">${suggestions || "<li>—</li>"}</ul>
      </div>
    </div>
  `;
}

function onAnalysisError(data) {
  if (evtSource) { evtSource.close(); evtSource = null; }
  document.getElementById("analysis-body").innerHTML =
    `<div class="analysis-error">Analysis failed: ${data.error || "unknown error"}</div>`;
}

