import os
import time
import json
from typing import Optional
from openai import OpenAI

from dotenv import load_dotenv
load_dotenv()

_client = OpenAI(api_key=os.getenv("OPENAI_API_KEY"))

# ------------------------------------------------------------------
# Tool definitions (OpenAI function calling format)
# ------------------------------------------------------------------

TOOLS = [
    {
        "type": "function",
        "function": {
            "name": "ask_dm",
            "description": "Ask the Dungeon Master for information. They see the full map but their data is delayed by several turns — their answer may be outdated. Response arrives on your NEXT turn.",
            "parameters": {
                "type": "object",
                "properties": {
                    "question": {
                        "type": "string",
                        "description": "Your question, e.g. 'Where is the key?', 'Where is the door?', 'Where is the exit?', 'Where is Agent B?'",
                    }
                },
                "required": ["question"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "move",
            "description": "Move one step in a cardinal direction.",
            "parameters": {
                "type": "object",
                "properties": {
                    "direction": {
                        "type": "string",
                        "enum": ["north", "south", "east", "west"],
                    }
                },
                "required": ["direction"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "look",
            "description": "Observe your current position and all adjacent cells.",
            "parameters": {"type": "object", "properties": {}, "required": []},
        },
    },
    {
        "type": "function",
        "function": {
            "name": "pick_up",
            "description": "Pick up an item on your current cell.",
            "parameters": {"type": "object", "properties": {}, "required": []},
        },
    },
    {
        "type": "function",
        "function": {
            "name": "use_item",
            "description": "Use an item from your inventory on a target.",
            "parameters": {
                "type": "object",
                "properties": {
                    "item":   {"type": "string", "description": "Item name, e.g. 'key'"},
                    "target": {"type": "string", "description": "Target name, e.g. 'door'"},
                },
                "required": ["item", "target"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "send_message",
            "description": "Send a message to the other agent. Delivered on their next turn.",
            "parameters": {
                "type": "object",
                "properties": {
                    "text": {"type": "string", "description": "The message text"}
                },
                "required": ["text"],
            },
        },
    },
]

SYSTEM_PROMPT = """You are an explorer agent in a dungeon grid. Your goal: reach the exit (E).

Grid symbols:
  .  empty floor
  #  wall (impassable)
  K  key (pick it up with pick_up)
  D  locked door (use_item key door when standing adjacent to it)
  O  open door (passable)
  E  exit — move onto it to win
  A / B  the two agents

Rules:
- Fog of war: you can only see your current cell and the 8 cells around you.
- One agent must find the key (K) and unlock the door (D) before either can pass through.
- Messages arrive on the OTHER agent's NEXT turn (1-turn delay).
- The Dungeon Master (DM) sees the full map but their info is several turns old — use ask_dm when lost.
- You MUST call exactly one tool per turn.

Strategy:
- If you see K nearby, move there and pick_up.
- If you have the key and D is adjacent, use_item key door immediately.
- If you see E, move onto it.
- If lost, use ask_dm("Where is the key?") or ask_dm("Where is the exit?") — but remember the answer may be stale.
- Otherwise, MOVE to explore. Do not call look repeatedly.
- Use send_message to share discoveries with the other agent.

Your agent ID: {agent_id}
"""


class Agent:
    def __init__(self, agent_id: str, model: str = "gpt-4o-mini"):
        self.agent_id = agent_id
        self.model = model
        self.last_result: Optional[dict] = None   # result of previous turn's action

    # ------------------------------------------------------------------
    # Decision
    # ------------------------------------------------------------------

    def decide(self, observable_state: dict, messages_received: list[str]) -> tuple[dict, str, str, int]:
        """
        Returns (tool_call_dict, full_prompt_str, raw_response_str, latency_ms)
        """
        obs_text = _format_observation(observable_state, messages_received, self.last_result)

        # Stateless per turn — predictable context window, easier to trace
        messages = [
            {"role": "system", "content": SYSTEM_PROMPT.format(agent_id=self.agent_id)},
            {"role": "user",   "content": obs_text},
        ]

        start = time.time()
        response = _client.chat.completions.create(
            model=self.model,
            messages=messages,
            tools=TOOLS,
            tool_choice="required",
        )
        latency_ms = int((time.time() - start) * 1000)

        raw_response = response.model_dump_json()
        choice = response.choices[0]

        # Extract tool call
        tool_call = choice.message.tool_calls[0] if choice.message.tool_calls else None
        if tool_call is None:
            # Fallback: look if no tool was chosen
            tool_dict = {"tool": "look", "args": {}}
        else:
            try:
                args = json.loads(tool_call.function.arguments)
            except json.JSONDecodeError:
                args = {}
            tool_dict = {"tool": tool_call.function.name, "args": args}

        return tool_dict, obs_text, raw_response, latency_ms


# ------------------------------------------------------------------
# Helpers
# ------------------------------------------------------------------

def _format_observation(obs: dict, messages: list[str], last_result: Optional[dict] = None) -> str:
    lines = [
        f"Your position: {obs['position']}",
        f"Inventory: {obs['inventory'] or 'empty'}",
        f"Door unlocked: {obs['door_unlocked']}",
        "",
        "Visible cells (row,col → cell):",
    ]
    for coord, cell in sorted(obs["visible_cells"].items()):
        lines.append(f"  {coord} → {cell}")

    if obs["other_agent_visible"]:
        lines.append(f"\nOther agent is visible at {obs['other_agent_position']}")
    else:
        lines.append("\nOther agent is not in view")

    if last_result is not None:
        success = last_result.get("success", True)
        if not success:
            lines.append(f"\nLast action FAILED: {last_result.get('reason', 'unknown reason')}. Try something different.")
        else:
            lines.append(f"\nLast action succeeded.")

    if messages:
        lines.append("\nMessages received this turn:")
        for m in messages:
            lines.append(f"  - {m}")
    else:
        lines.append("\nNo messages received this turn.")

    lines.append("\nWhat do you do? Call exactly one tool.")
    return "\n".join(lines)

import random
from enum import Enum
from typing import Optional

class Cell(str, Enum):
    EMPTY   = "."
    WALL    = "#"
    KEY     = "K"
    DOOR    = "D"   # locked
    OPEN    = "O"   # door unlocked/open
    EXIT    = "E"
    AGENT_A = "A"
    AGENT_B = "B"

DIRECTIONS = {
    "north": (-1, 0),
    "south": ( 1, 0),
    "east":  ( 0, 1),
    "west":  ( 0,-1),
}

class DungeonWorld:
    def __init__(self, size: int = 10, seed: Optional[int] = None):
        self.size = size
        self.rng = random.Random(seed)
        self.grid: list[list[str]] = []
        self.agent_positions: dict[str, tuple[int,int]] = {}
        self.agent_inventories: dict[str, list[str]] = {"A": [], "B": []}
        self.door_pos: Optional[tuple[int,int]] = None
        self.key_pos: Optional[tuple[int,int]] = None
        self.exit_pos: Optional[tuple[int,int]] = None
        self.door_unlocked = False
        self._build()

    # ------------------------------------------------------------------
    # World construction
    # ------------------------------------------------------------------

    def _build(self):
        s = self.size
        # Start with all empty
        self.grid = [[Cell.EMPTY for _ in range(s)] for _ in range(s)]

        # Outer walls
        for i in range(s):
            self.grid[0][i] = Cell.WALL
            self.grid[s-1][i] = Cell.WALL
            self.grid[i][0] = Cell.WALL
            self.grid[i][s-1] = Cell.WALL

        # Random interior obstacles (~15% of inner cells)
        inner_cells = [(r, c) for r in range(1, s-1) for c in range(1, s-1)]
        obstacle_count = max(1, int(len(inner_cells) * 0.15))
        obstacles = self.rng.sample(inner_cells, obstacle_count)
        for r, c in obstacles:
            self.grid[r][c] = Cell.WALL

        # Place special cells on remaining empty inner cells.
        # Filter to cells that have at least one non-wall neighbour so
        # agents are never immediately boxed in.
        def has_open_neighbour(r, c):
            for dr, dc in DIRECTIONS.values():
                nr, nc = r + dr, c + dc
                if 0 <= nr < s and 0 <= nc < s and self.grid[nr][nc] == Cell.EMPTY:
                    return True
            return False

        available = [
            pos for pos in inner_cells
            if self.grid[pos[0]][pos[1]] == Cell.EMPTY and has_open_neighbour(*pos)
        ]
        self.rng.shuffle(available)

        self.key_pos  = available.pop()
        self.door_pos = available.pop()
        self.exit_pos = available.pop()
        a_start       = available.pop()
        b_start       = available.pop()

        self.grid[self.key_pos[0]][self.key_pos[1]]   = Cell.KEY
        self.grid[self.door_pos[0]][self.door_pos[1]] = Cell.DOOR
        self.grid[self.exit_pos[0]][self.exit_pos[1]] = Cell.EXIT

        self.agent_positions["A"] = a_start
        self.agent_positions["B"] = b_start

    # ------------------------------------------------------------------
    # Observation (fog of war)
    # ------------------------------------------------------------------

    def get_visible_cells(self, agent_id: str) -> dict:
        """Returns the 3x3 neighbourhood centred on the agent."""
        r, c = self.agent_positions[agent_id]
        visible = {}
        for dr in range(-1, 2):
            for dc in range(-1, 2):
                nr, nc = r + dr, c + dc
                if 0 <= nr < self.size and 0 <= nc < self.size:
                    cell_val = self.grid[nr][nc]
                    # Show agent markers
                    other = "B" if agent_id == "A" else "A"
                    if (nr, nc) == self.agent_positions.get(other):
                        cell_val = Cell(f"AGENT_{other}") if False else other
                    visible[(nr, nc)] = cell_val
                else:
                    visible[(nr, nc)] = Cell.WALL  # out of bounds = wall
        return visible

    def observable_state(self, agent_id: str) -> dict:
        pos = self.agent_positions[agent_id]
        visible = self.get_visible_cells(agent_id)
        other = "B" if agent_id == "A" else "A"
        other_pos = self.agent_positions[other]
        other_visible = other_pos in visible

        return {
            "position": list(pos),
            "inventory": list(self.agent_inventories[agent_id]),
            "visible_cells": {
                f"{r},{c}": str(v.value) if hasattr(v, 'value') else str(v)
                for (r, c), v in visible.items()
            },
            "other_agent_visible": other_visible,
            "other_agent_position": list(other_pos) if other_visible else None,
            "door_unlocked": self.door_unlocked,
        }

    # ------------------------------------------------------------------
    # Actions
    # ------------------------------------------------------------------

    def move(self, agent_id: str, direction: str) -> dict:
        if direction not in DIRECTIONS:
            return {"success": False, "reason": f"Unknown direction '{direction}'"}

        r, c = self.agent_positions[agent_id]
        dr, dc = DIRECTIONS[direction]
        nr, nc = r + dr, c + dc

        if not (0 <= nr < self.size and 0 <= nc < self.size):
            return {"success": False, "reason": "Out of bounds"}

        cell = self.grid[nr][nc]

        if cell == Cell.WALL:
            return {"success": False, "reason": "Wall in the way"}

        if cell == Cell.DOOR:
            return {"success": False, "reason": "Locked door blocks the way"}

        self.agent_positions[agent_id] = (nr, nc)
        cell_str = cell.value if hasattr(cell, 'value') else str(cell)
        return {"success": True, "new_position": [nr, nc], "cell_entered": cell_str}

    def pick_up(self, agent_id: str) -> dict:
        r, c = self.agent_positions[agent_id]
        cell = self.grid[r][c]

        if cell == Cell.KEY:
            self.agent_inventories[agent_id].append("key")
            self.grid[r][c] = Cell.EMPTY
            self.key_pos = None
            return {"success": True, "item": "key"}

        return {"success": False, "reason": "Nothing to pick up here"}

    def use_item(self, agent_id: str, item: str, target: str) -> dict:
        if item != "key":
            return {"success": False, "reason": f"Don't know how to use '{item}'"}

        if target != "door":
            return {"success": False, "reason": f"Can't use key on '{target}'"}

        if "key" not in self.agent_inventories[agent_id]:
            return {"success": False, "reason": "You don't have the key"}

        r, c = self.agent_positions[agent_id]
        # Must be adjacent to door
        for dr, dc in DIRECTIONS.values():
            nr, nc = r + dr, c + dc
            if (nr, nc) == self.door_pos:
                self.agent_inventories[agent_id].remove("key")
                self.grid[self.door_pos[0]][self.door_pos[1]] = Cell.OPEN
                self.door_unlocked = True
                return {"success": True, "result": "Door is now open"}

        return {"success": False, "reason": "Not adjacent to the door"}

    # ------------------------------------------------------------------
    # World truth snapshot (for divergence detection)
    # ------------------------------------------------------------------

    def world_snapshot(self) -> dict:
        return {
            "agent_positions": {k: list(v) for k, v in self.agent_positions.items()},
            "key_location": list(self.key_pos) if self.key_pos else None,
            "door_location": list(self.door_pos) if self.door_pos else None,
            "door_unlocked": self.door_unlocked,
            "exit_location": list(self.exit_pos) if self.exit_pos else None,
            "inventories": {k: list(v) for k, v in self.agent_inventories.items()},
        }

    def grid_layout(self) -> list:
        """Serialize grid as 2D list of cell characters for the browser."""
        return [
            [cell.value if hasattr(cell, 'value') else str(cell) for cell in row]
            for row in self.grid
        ]

    def is_at_exit(self, agent_id: str) -> bool:
        return self.agent_positions[agent_id] == self.exit_pos

    def render(self) -> str:
        """ASCII render of the full grid (for debugging/logs)."""
        grid_copy = [row[:] for row in self.grid]
        for agent_id, (r, c) in self.agent_positions.items():
            grid_copy[r][c] = agent_id
        return "\n".join("".join(row) for row in grid_copy)

