import os
import time
import json
from typing import Optional
from openai import OpenAI

from dotenv import load_dotenv
load_dotenv()

_client = OpenAI(api_key=os.getenv("OPENAI_API_KEY"))

# ------------------------------------------------------------------
# Tool definitions (OpenAI function calling format)
# ------------------------------------------------------------------

TOOLS = [
    {
        "type": "function",
        "function": {
            "name": "ask_dm",
            "description": "Ask the Dungeon Master for information. They see the full map but their data is delayed by several turns — their answer may be outdated. Response arrives on your NEXT turn.",
            "parameters": {
                "type": "object",
                "properties": {
                    "question": {
                        "type": "string",
                        "description": "Your question, e.g. 'Where is the key?', 'Where is the door?', 'Where is the exit?', 'Where is Agent B?'",
                    }
                },
                "required": ["question"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "move",
            "description": "Move one step in a cardinal direction.",
            "parameters": {
                "type": "object",
                "properties": {
                    "direction": {
                        "type": "string",
                        "enum": ["north", "south", "east", "west"],
                    }
                },
                "required": ["direction"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "look",
            "description": "Observe your current position and all adjacent cells. Only use this if you have a specific reason — prefer moving to explore.",
            "parameters": {"type": "object", "properties": {}, "required": []},
        },
    },
    {
        "type": "function",
        "function": {
            "name": "pick_up",
            "description": "Pick up an item on your current cell.",
            "parameters": {"type": "object", "properties": {}, "required": []},
        },
    },
    {
        "type": "function",
        "function": {
            "name": "use_item",
            "description": "Use an item from your inventory on a target.",
            "parameters": {
                "type": "object",
                "properties": {
                    "item":   {"type": "string", "description": "Item name, e.g. 'key'"},
                    "target": {"type": "string", "description": "Target name, e.g. 'door'"},
                },
                "required": ["item", "target"],
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "send_message",
            "description": "Send a message to the other agent. Delivered on their next turn.",
            "parameters": {
                "type": "object",
                "properties": {
                    "text": {"type": "string", "description": "The message text"}
                },
                "required": ["text"],
            },
        },
    },
]

SYSTEM_PROMPT = """You are an explorer agent in a dungeon grid. Your goal: BOTH agents must reach the exit (E).

Grid symbols:
  .  empty floor      #  wall (impassable)
  K  key              D  locked door (needs key)
  O  open door        E  exit
  A / B  the agents

Rules:
- Fog of war: you can only see a 3x3 area around you.
- One agent must find K, pick it up, and use it on D to unlock it. Then both reach E.
- Messages to your partner arrive on their NEXT turn.
- The DM sees the full map but their snapshot is several turns old — useful but possibly stale.
- You MUST call exactly one tool per turn.

Strategy (follow in strict priority order):

1. TURN 0 ONLY — If you have no landmark locations known yet: ask_dm("Where is the key, door, and exit? Give row and col for each.")
   Do this exactly once. Once you have coordinates, never ask the DM the same question again — navigate instead.

2. KEY PICKUP — If you are standing on K (visible in your current cell): pick_up immediately.

3. UNLOCK — If you have the key and are adjacent to D: use_item key door immediately.

4. NAVIGATE TO TARGET — If you know a landmark's coordinates (from DM or messages), move toward it:
   Use the navigation hint provided below — it tells you exactly which direction to go.

5. SHARE DISCOVERIES — After picking up the key OR finding exit/door for the first time,
   send_message ONCE to your partner. Only share facts you have directly observed.
   Do NOT claim to have items you do not have (check your inventory first).
   Format: "KEY at row=R col=C" / "DOOR at row=R col=C" / "EXIT at row=R col=C" / "I PICKED UP THE KEY"

6. LOOPING DETECTED — If the observation shows a loop warning, follow its instruction exactly.
   If it says navigate to exit, move toward exit. If it says ask_dm, ask once then move.

7. EXPLORE — If you have no target: move in a direction not in your recent path.
   Never call look when you could move.

Your agent ID: {agent_id}
"""


class Agent:
    def __init__(self, agent_id: str, model: str = "gpt-4o-mini"):
        self.agent_id   = agent_id
        self.model      = model
        self.last_result: Optional[dict] = None

        # Cross-turn state for loop detection and landmark memory
        self.recent_positions: list  = []          # last 12 positions as (row, col) tuples
        self.known_landmarks:  dict  = {}          # {"key": [r,c], "door": [r,c], "exit": [r,c]}
        self.turn_count:       int   = 0

    def update_knowledge(self, obs: dict):
        """
        Called by the game loop before decide() each turn.
        Updates landmark memory from visible cells and tracks position history.
        """
        pos = obs.get("position")
        if pos:
            self.recent_positions.append(tuple(pos))
            if len(self.recent_positions) > 12:
                self.recent_positions.pop(0)

        # Learn landmark locations from what's currently visible
        for coord_str, cell in obs.get("visible_cells", {}).items():
            r, c = map(int, coord_str.split(","))
            if cell == "K" and "key" not in self.known_landmarks:
                self.known_landmarks["key"] = [r, c]
            if cell in ("D", "O") and "door" not in self.known_landmarks:
                self.known_landmarks["door"] = [r, c]
            if cell == "E" and "exit" not in self.known_landmarks:
                self.known_landmarks["exit"] = [r, c]

        # If we're carrying the key, it's no longer on the floor
        if "key" in obs.get("inventory", []):
            self.known_landmarks.pop("key", None)

        # If the door is already unlocked, key is gone and door no longer matters
        if obs.get("door_unlocked"):
            self.known_landmarks.pop("key", None)
            self.known_landmarks.pop("door", None)
            self.known_landmarks.pop("door_open", None)

        self.turn_count += 1

    @property
    def is_looping(self) -> bool:
        """True if the agent has been cycling through ≤3 unique cells in the last 10 moves."""
        if len(self.recent_positions) < 10:
            return False
        return len(set(self.recent_positions[-10:])) <= 3

    # ------------------------------------------------------------------
    # Decision
    # ------------------------------------------------------------------

    def decide(self, observable_state: dict, messages_received: list[str]) -> tuple[dict, str, str, int]:
        """Returns (tool_call_dict, prompt_str, raw_response_str, latency_ms)"""
        obs_text = _format_observation(
            observable_state,
            messages_received,
            self.last_result,
            self.known_landmarks,
            self.recent_positions,
            self.is_looping,
            self.turn_count,
        )

        messages = [
            {"role": "system", "content": SYSTEM_PROMPT.format(agent_id=self.agent_id)},
            {"role": "user",   "content": obs_text},
        ]

        start = time.time()
        response = _client.chat.completions.create(
            model=self.model,
            messages=messages,
            tools=TOOLS,
            tool_choice="required",
        )
        latency_ms = int((time.time() - start) * 1000)

        raw_response = response.model_dump_json()
        choice       = response.choices[0]

        tool_call = choice.message.tool_calls[0] if choice.message.tool_calls else None
        if tool_call is None:
            tool_dict = {"tool": "look", "args": {}}
        else:
            try:
                args = json.loads(tool_call.function.arguments)
            except json.JSONDecodeError:
                args = {}
            tool_dict = {"tool": tool_call.function.name, "args": args}

        return tool_dict, obs_text, raw_response, latency_ms


# ------------------------------------------------------------------
# Helpers
# ------------------------------------------------------------------

def _nav_hint(from_pos: list, to_pos: list) -> str:
    """
    Compute cardinal directions to move from from_pos toward to_pos.
    Returns a human-readable hint like 'go north (3 steps) then east (5 steps)'.
    """
    dr = to_pos[0] - from_pos[0]
    dc = to_pos[1] - from_pos[1]
    parts = []
    if dr < 0:
        parts.append(f"north ({abs(dr)} step{'s' if abs(dr) > 1 else ''})")
    elif dr > 0:
        parts.append(f"south ({dr} step{'s' if dr > 1 else ''})")
    if dc < 0:
        parts.append(f"west ({abs(dc)} step{'s' if abs(dc) > 1 else ''})")
    elif dc > 0:
        parts.append(f"east ({dc} step{'s' if dc > 1 else ''})")
    if not parts:
        return "you are already there"
    manhattan = abs(dr) + abs(dc)
    return f"go {' then '.join(parts)}  (Manhattan distance: {manhattan})"


def _format_observation(
    obs:               dict,
    messages:          list,
    last_result:       Optional[dict],
    known_landmarks:   dict,
    recent_positions:  list,
    is_looping:        bool,
    turn_count:        int,
) -> str:
    pos = obs["position"]
    r, c = pos

    door_status = "YES — door is open, head straight to the EXIT" if obs['door_unlocked'] else "NO — someone must find the key and unlock it first"
    lines = [
        f"Turn: {turn_count}",
        f"Your position: row={r}, col={c}",
        f"Inventory: {obs['inventory'] or 'empty'}",
        f"Door unlocked: {door_status}",
        "",
        "Visible cells (row,col → cell type):",
    ]
    for coord, cell in sorted(obs["visible_cells"].items()):
        lines.append(f"  {coord} → {cell}")

    # Other agent
    if obs["other_agent_visible"]:
        op = obs["other_agent_position"]
        lines.append(f"\nPartner visible at row={op[0]}, col={op[1]}")
    else:
        lines.append("\nPartner not in view")

    # Known landmarks + navigation hints
    if known_landmarks:
        lines.append("\nKnown landmark locations — USE THESE TO NAVIGATE, do not ask_dm again:")
        for name, lpos in known_landmarks.items():
            hint = _nav_hint(pos, lpos)
            lines.append(f"  {name.upper()}: row={lpos[0]}, col={lpos[1]}  → {hint}")
    else:
        lines.append("\nNo landmark locations known yet. Use ask_dm ONCE to get coordinates.")

    # Loop warning — context-aware: if exit is known, navigate there; otherwise ask DM
    if is_looping:
        unique = len(set(recent_positions[-10:]))
        if "exit" in known_landmarks:
            ep = known_landmarks["exit"]
            lines.append(
                f"\n⚠ LOOP WARNING: visiting only {unique} unique cells in last 10 moves."
                f" You already know the EXIT is at row={ep[0]}, col={ep[1]}. Navigate there NOW — do not ask_dm."
            )
        else:
            lines.append(
                f"\n⚠ LOOP WARNING: visiting only {unique} unique cells in last 10 moves."
                f" You are going in circles. Use ask_dm to get coordinates."
            )
    elif len(recent_positions) >= 4:
        recent_str = " → ".join(f"r{p[0]},c{p[1]}" for p in recent_positions[-4:])
        lines.append(f"\nRecent path (last 4): {recent_str}")

    # Last action feedback
    if last_result is not None:
        if not last_result.get("success", True):
            lines.append(f"\nLast action FAILED: {last_result.get('reason', 'unknown')}. Try something different.")
        else:
            lines.append("\nLast action succeeded.")

    # Messages
    if messages:
        lines.append("\nMessages from partner this turn:")
        for m in messages:
            lines.append(f"  {m}")
    else:
        lines.append("\nNo messages from partner this turn.")

    lines.append("\nWhat do you do? Call exactly one tool.")
    return "\n".join(lines)

from world import DungeonWorld
from agents import Agent
from tracer import Tracer
from typing import Optional, Callable

# Thresholds for cross-agent diagnostics
COORDINATION_GAP_THRESHOLD = 10   # turns of silence before flagging
STAGNATION_THRESHOLD       = 5    # turns in same position before flagging


class GameLoop:
    def __init__(
        self,
        world: DungeonWorld,
        agent_a: Agent,
        agent_b: Agent,
        tracer: Tracer,
        max_turns: int = 100,
        on_event: Optional[Callable] = None,
        dm=None,
    ):
        self.world     = world
        self.agents    = {"A": agent_a, "B": agent_b}
        self.tracer    = tracer
        self.max_turns = max_turns
        self.on_event  = on_event
        self.dm        = dm

        self._pending_messages: dict[str, list[str]] = {"A": [], "B": []}

        # Repeated-failure tracking (same failing action in a row)
        self._repeat_failures: dict[str, int]          = {"A": 0, "B": 0}
        self._last_action:     dict[str, Optional[str]] = {"A": None, "B": None}

        # Coordination gap: turns since any inter-agent message was exchanged
        self._last_message_turn: int = -1

        # Stagnation: turns each agent has spent without changing position
        self._last_positions:   dict[str, Optional[list]] = {"A": None, "B": None}
        self._turns_stationary: dict[str, int]             = {"A": 0,    "B": 0}

    # ------------------------------------------------------------------

    def run(self) -> str:
        order = ["A", "B"]
        turn  = 0

        print(f"\n{'='*40}")
        print(f"Run {self.tracer.run_id[:8]} starting")
        print(self.world.render())
        print(f"{'='*40}\n")

        while turn < self.max_turns:
            agent_id = order[turn % 2]
            agent    = self.agents[agent_id]

            # Deliver queued messages
            messages_received                  = self._pending_messages[agent_id]
            self._pending_messages[agent_id]   = []

            # Snapshot BEFORE action — this is what the agent's belief is compared against
            obs          = self.world.observable_state(agent_id)
            world_before = self.world.world_snapshot()

            # DM records state before each turn
            if self.dm:
                self.dm.record(turn, world_before)

            # Update agent's cross-turn knowledge (landmarks, loop detection)
            agent.update_knowledge(obs)

            # Agent decides
            tool_call, prompt, raw_response, latency_ms = agent.decide(obs, messages_received)

            # Execute tool
            result      = self._execute_tool(agent_id, tool_call, agent, turn)
            agent.last_result = result
            world_after = self.world.world_snapshot()

            # Sync landmark memory across both agents after key events
            if tool_call.get("tool") == "pick_up" and result.get("item") == "key":
                # Key is off the floor — both agents should stop navigating to it
                for ag in self.agents.values():
                    ag.known_landmarks.pop("key", None)
            if tool_call.get("tool") == "use_item" and result.get("success"):
                # Key consumed, door open — both agents clear key and door from landmarks.
                # They should now navigate to exit only.
                for ag in self.agents.values():
                    ag.known_landmarks.pop("key", None)
                    ag.known_landmarks.pop("door", None)

            # ── Repeated-failure tracking ──────────────────────────────
            action_key = f"{tool_call['tool']}:{tool_call.get('args', {})}"
            if not result.get("success", True) and action_key == self._last_action[agent_id]:
                self._repeat_failures[agent_id] += 1
            else:
                self._repeat_failures[agent_id] = 0
            self._last_action[agent_id] = action_key

            # ── Stagnation tracking ────────────────────────────────────
            cur_pos = world_after["agent_positions"][agent_id]
            if self._last_positions[agent_id] == cur_pos:
                self._turns_stationary[agent_id] += 1
            else:
                self._turns_stationary[agent_id] = 0
            self._last_positions[agent_id] = cur_pos

            # ── Coordination gap ───────────────────────────────────────
            coordination_gap = (
                turn - self._last_message_turn
                if self._last_message_turn >= 0
                else turn
            )

            # ── Build extra divergences ────────────────────────────────
            extra_divergences = []
            if coordination_gap >= COORDINATION_GAP_THRESHOLD:
                extra_divergences.append({
                    "type":      "coordination_gap",
                    "gap_turns": coordination_gap,
                    "note":      f"No inter-agent communication for {coordination_gap} turns",
                })
            if self._turns_stationary[agent_id] >= STAGNATION_THRESHOLD:
                extra_divergences.append({
                    "type":             "agent_stagnation",
                    "agent":            agent_id,
                    "turns_stationary": self._turns_stationary[agent_id],
                    "position":         cur_pos,
                    "note":             f"Agent {agent_id} has not moved for {self._turns_stationary[agent_id]} turns",
                })

            belief_state = {**obs, "messages_received": messages_received}

            event = self.tracer.log_turn(
                turn=turn,
                agent=agent_id,
                phase="action",
                action=tool_call,
                result=result,
                belief_state=belief_state,
                world_truth=world_before,       # ← FIXED: belief vs truth at decision time
                llm_prompt=prompt,
                llm_response=raw_response,
                latency_ms=latency_ms,
                extra_divergences=extra_divergences,
                extra={
                    "repeat_failures":    self._repeat_failures[agent_id],
                    "coordination_gap":   coordination_gap,
                    "turns_stationary":   self._turns_stationary[agent_id],
                    "messages_in_flight": {k: list(v) for k, v in self._pending_messages.items()},
                },
            )

            print(
                f"Turn {turn:3d} | Agent {agent_id} | "
                f"{tool_call['tool']}({tool_call['args']}) → {result}"
            )

            # SSE — includes positions_after separately so the SVG trail is correct
            if self.on_event:
                self.on_event({
                    "type":           "turn",
                    **event,
                    "positions_after": world_after["agent_positions"],
                    "messages_in_flight": {k: list(v) for k, v in self._pending_messages.items()},
                })

            # Win
            if self._both_at_exit():
                print(f"\nBoth agents reached the exit on turn {turn}!")
                self.tracer.log_run_end("success", turn)
                if self.on_event:
                    self.on_event({"type": "run_end", "outcome": "success",
                                   "total_turns": turn, "run_id": self.tracer.run_id})
                return "success"

            if self.world.is_at_exit(agent_id):
                print(f"  Agent {agent_id} reached the exit (waiting for partner)")

            turn += 1

        print(f"\nTurn limit ({self.max_turns}) reached.")
        self.tracer.log_run_end("turn_limit", turn)
        if self.on_event:
            self.on_event({"type": "run_end", "outcome": "turn_limit",
                           "total_turns": turn, "run_id": self.tracer.run_id})
        return "turn_limit"

    # ------------------------------------------------------------------
    # Tool execution
    # ------------------------------------------------------------------

    def _execute_tool(self, agent_id: str, tool_call: dict, agent: Agent, turn: int = 0) -> dict:
        tool = tool_call.get("tool", "look")
        args = tool_call.get("args", {})

        if tool == "move":
            return self.world.move(agent_id, args.get("direction", "north"))

        if tool == "look":
            return {"success": True, "observation": self.world.observable_state(agent_id)}

        if tool == "pick_up":
            return self.world.pick_up(agent_id)

        if tool == "use_item":
            return self.world.use_item(agent_id, args.get("item", ""), args.get("target", ""))

        if tool == "send_message":
            text      = args.get("text", "")
            recipient = "B" if agent_id == "A" else "A"
            self._pending_messages[recipient].append(f"[Agent {agent_id}]: {text}")
            self._last_message_turn = turn          # update coordination gap clock
            return {"success": True, "delivered_to": recipient, "on_turn": "next"}

        if tool == "ask_dm":
            return self._handle_ask_dm(agent_id, args.get("question", ""), turn)

        return {"success": False, "reason": f"Unknown tool '{tool}'"}

    def _handle_ask_dm(self, agent_id: str, question: str, turn: int) -> dict:
        if not self.dm:
            return {"success": False, "reason": "No Dungeon Master in this run"}

        current_truth = self.world.world_snapshot()
        dm_result     = self.dm.answer(agent_id, question, turn)

        # Populate the agent's landmark memory directly from the DM's stale snapshot.
        # This gives the agent structured coordinates to navigate with, not just text.
        # Uses stale data intentionally — divergences are still detected by the tracer.
        snap = dm_result.get("stale_snapshot", {})
        agent = self.agents[agent_id]
        if snap.get("key_location") and "key" not in agent.known_landmarks:
            agent.known_landmarks["key"] = snap["key_location"]
        if snap.get("door_location") and "door" not in agent.known_landmarks:
            agent.known_landmarks["door"] = snap["door_location"]
        if snap.get("exit_location") and "exit" not in agent.known_landmarks:
            agent.known_landmarks["exit"] = snap["exit_location"]

        dm_event = self.tracer.log_dm_interaction(
            turn=turn,
            asker=agent_id,
            question=question,
            dm_result=dm_result,
            current_truth=current_truth,
        )

        self._pending_messages[agent_id].append(
            f"[Dungeon Master, {dm_result['actual_staleness']} turns stale]: {dm_result['answer']}"
        )

        print(f"         DM → Agent {agent_id} (staleness={dm_result['actual_staleness']}): "
              f"{dm_result['answer'][:60]}…")

        if self.on_event:
            self.on_event({
                "type":                  "dm_interaction",
                "turn":                  turn,
                "asker":                 agent_id,
                "question":              question,
                "answer":                dm_result["answer"],
