// ── run_end ───────────────────────────────────────────────────────────────────
function onRunEnd(data) {
  setBadge(data.outcome);
  document.getElementById("run-btn").disabled  = false;
  document.getElementById("run-btn").textContent = "▶ Run";
  document.getElementById("download-btn").disabled = false;
  // Keep evtSource open — waiting for analysis event

  // End-of-run banner in log
  const banner = document.createElement("div");
  banner.className = `log-banner log-banner--${data.outcome}`;
  banner.innerHTML = `
    <strong>${outcomeLabel(data.outcome)}</strong>
    <span>${data.total_turns} turns · ${divergeCount} divergence${divergeCount !== 1 ? "s" : ""} detected</span>
  `;
  document.getElementById("event-log").appendChild(banner);
  scrollLog();

  // Show analysis panel with loading state
  const panel = document.getElementById("analysis-panel");
  panel.classList.remove("hidden");
  document.getElementById("analysis-body").innerHTML =
    '<div class="analysis-loading">⏳ Generating analysis…</div>';

  loadRunHistory();
}

// ── analysis ──────────────────────────────────────────────────────────────────
function onAnalysis(data) {
  if (evtSource) { evtSource.close(); evtSource = null; }

  const failureType = data.failure_type || "unknown";
  const badgeClass  = {
    success:      "badge--success",
    single_agent: "badge--turn_limit",
    interaction:  "badge--turn_limit",
    emergent:     "badge--stuck",
  }[failureType] || "badge--unknown";

  document.getElementById("analysis-failure-badge").innerHTML =
    `<span class="badge ${badgeClass}">${failureType.replace(/_/g, " ")}</span>`;
  document.getElementById("analysis-subtitle").textContent = "";

  const suggestions = (data.what_should_change || "")
    .split("\n")
    .filter(l => l.trim())
    .map(l => `<li>${l.replace(/^-\s*/, "")}</li>`)
    .join("");

  document.getElementById("analysis-body").innerHTML = `
    <div class="analysis-grid">
      <div class="analysis-section">
        <div class="analysis-label">What happened</div>
        <p>${data.what_happened || "—"}</p>
      </div>
      <div class="analysis-section">
        <div class="analysis-label">Why it happened</div>
        <p>${data.why_it_happened || "—"}</p>
      </div>
      <div class="analysis-section analysis-section--wide">
        <div class="analysis-label">What should change</div>
        <ul class="analysis-suggestions">${suggestions || "<li>—</li>"}</ul>
      </div>
    </div>
  `;
}

function onAnalysisError(data) {
  if (evtSource) { evtSource.close(); evtSource = null; }
  document.getElementById("analysis-body").innerHTML =
    `<div class="analysis-error">Analysis failed: ${data.error || "unknown error"}</div>`;
}

// ── SVG dungeon ───────────────────────────────────────────────────────────────
function buildSVG(data) {
  const container = document.getElementById("dungeon-container");
  container.innerHTML = "";

  const n    = data.size;
  const dim  = n * STEP + GAP;
  const svg  = document.createElementNS(NS, "svg");
  svg.id = "dungeon-svg";
  svg.setAttribute("width",   dim);
  svg.setAttribute("height",  dim);
  svg.setAttribute("viewBox", `0 0 ${dim} ${dim}`);

  // Layer order: bg → trails → agents
  ["layer-bg", "layer-trail-A", "layer-trail-B", "layer-agents"].forEach(id => {
    const g = document.createElementNS(NS, "g");
    g.id = id;
    svg.appendChild(g);
  });

  // Draw static grid
  const bg = svg.querySelector("#layer-bg");
  data.grid.forEach((row, r) => {
    row.forEach((cell, c) => {
      const rect = makeSVGRect(c * STEP + GAP, r * STEP + GAP, CELL, CELL, cellBg(cell));
      rect.id = `cell-${r}-${c}`;
      bg.appendChild(rect);

      // Label for special cells
      if ("KDOEkdoe".includes(cell) && cell !== ".") {
        const txt = makeSVGText(cellCx(c), cellCy(r), cell.toUpperCase(), cellFg(cell));
        bg.appendChild(txt);
      }
    });
  });

  // Initial agent positions
  const agLayer = svg.querySelector("#layer-agents");
  ["A", "B"].forEach(id => {
    const pos  = data.agent_positions[id];
    const [cx, cy] = toCXY(pos);
    trailPts[id] = [[cx, cy]];

    const circle = document.createElementNS(NS, "circle");
    circle.id = `agent-${id}`;
    circle.setAttribute("cx", cx);
    circle.setAttribute("cy", cy);
    circle.setAttribute("r",  11);
    circle.setAttribute("fill",         agentColor(id));
    circle.setAttribute("stroke",       "#0f1117");
    circle.setAttribute("stroke-width", "2");
    agLayer.appendChild(circle);

    const label = makeSVGText(cx, cy + 1, id, "#0f1117", "bold");
    label.id = `agent-label-${id}`;
    agLayer.appendChild(label);
  });

  // DM observer badge — floats outside the grid in the top-right corner
  const dmGroup = document.createElementNS(NS, "g");
  dmGroup.id = "dm-badge";
  const dmRect = makeSVGRect(dim - 52, 4, 48, 20, "rgba(224,145,74,0.15)");
  dmRect.setAttribute("rx", 4);
  const dmText = makeSVGText(dim - 28, 14, "◆ DM", "#e0914a", "700");
  dmText.setAttribute("font-size", "11");
  dmGroup.appendChild(dmRect);
  dmGroup.appendChild(dmText);
  svg.appendChild(dmGroup);

  container.appendChild(svg);
}

