    } else if (isStag) {
      detail = `<span class="div-believed">stationary for <code>${d.turns_stationary}</code> turns</span>`;
    } else if (d.believed !== undefined) {
      const fmt = v => Array.isArray(v) ? fmtPos(v) : JSON.stringify(v);
      detail = `<span class="div-believed">believed <code>${fmt(d.believed)}</code></span>
                <span class="div-truth">truth <code>${fmt(d.truth)}</code></span>`;
    } else if (d.note) {
      detail = `<span class="div-believed">${d.note}</span>`;
    }
    return `
    <div class="log-diverge">
      <span class="div-icon">⚑</span>
      <span class="div-type">${d.type.replace(/_/g," ")}</span>
      ${detail}
    </div>`;
  }).join("");
}

function renderMsgNote(data) {
  const text = data.action?.args?.text || "";
  const to   = data.agent === "A" ? "B" : "A";
  return `<div class="log-msg-note">→ Agent ${to} will receive this next turn: <em>"${text}"</em></div>`;
}

function renderMsgReceived(msgs) {
  return msgs.map(m =>
    `<div class="log-msg-received">📨 <em>${m}</em></div>`
  ).join("");
}

// ── Milestones ────────────────────────────────────────────────────────────────
function checkMilestones(data) {
  const wt  = data.world_truth || {};
  const res = data.result || {};
  const bar = document.getElementById("milestones");

  if (!MILESTONES.key_picked && res.item === "key") {
    MILESTONES.key_picked = data.turn;
    addMilestone(bar, `Key ✓ t${data.turn}`, "ms-key");
  }
  if (!MILESTONES.door_open && wt.door_unlocked) {
    MILESTONES.door_open = data.turn;
    addMilestone(bar, `Door ✓ t${data.turn}`, "ms-door");
  }
  if (!MILESTONES[`exit_${data.agent}`] && wt.agent_positions) {
    const pos  = wt.agent_positions[data.agent];
    const exit = wt.exit_location;
    if (exit && pos && pos[0] === exit[0] && pos[1] === exit[1]) {
      MILESTONES[`exit_${data.agent}`] = data.turn;
      addMilestone(bar, `${data.agent} exit t${data.turn}`, "ms-exit");
    }
  }
}

function addMilestone(bar, label, cls) {
  const el = document.createElement("span");
  el.className = `milestone ${cls}`;
  el.textContent = label;
  bar.appendChild(el);
}

// ── Divergence counter ────────────────────────────────────────────────────────
function trackDivergences(data) {
  if (data.divergences && data.divergences.length > 0) {
    divergeCount += data.divergences.length;
    const el = document.getElementById("divergence-counter");
    el.textContent = `${divergeCount} divergence${divergeCount !== 1 ? "s" : ""}`;
    el.classList.remove("hidden");
  }
}

// ── Past runs ─────────────────────────────────────────────────────────────────
function loadRunHistory() {
  fetch("/api/runs").then(r => r.json()).then(runs => {
    const wrap = document.getElementById("runs-table-wrap");
    if (!runs.length) { wrap.innerHTML = "<p class='empty'>No runs yet.</p>"; return; }
    wrap.innerHTML = `
      <table class="runs-table">
        <thead><tr>
          <th>Run ID</th><th>Outcome</th><th>Turns</th><th>Divergences</th><th></th>
        </tr></thead>
        <tbody>${runs.map(r => `
          <tr>
            <td class="mono">${r.run_id.slice(0,8)}</td>
            <td><span class="badge badge--${r.outcome}">${r.outcome}</span></td>
            <td>${r.total_turns}</td>
            <td class="${r.divergences > 0 ? "warn" : ""}">${r.divergences}</td>
            <td><a class="btn-small" href="/download/${r.run_id.slice(0,8)}">↓ JSON</a></td>
          </tr>`).join("")}
        </tbody>
      </table>`;
  });
}

// ── Helpers ───────────────────────────────────────────────────────────────────
